body {
  font-family: 'Merriweather', serif;
  font-size: 18px;
  line-height: 1.6;
  font-feature-settings: 'liga'; /* Enable standard ligatures */
}

h1 {
  font-family: 'Playfair Display', serif;
  font-size: 4em;
  font-weight: 700;
  font-feature-settings: 'liga', 'dlig'; /* Enable standard and discretionary ligatures for headlines */
}
